import {useState} from 'react';
const Home = () => {
    const [name, setName] = useState('kantiman ');
    const [age, setAge] = useState('32 ');

    const clickhandle = () => {
        setName('Amrit ');
        setAge('22 ')
    }

    return (
        <div className="home">
            <h1>Home page</h1>
            <p>{name}
                is {age}
                years old</p>
            <button onClick={clickhandle}>Click me</button>
        </div>
    );
}

export default Home;
